// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title BuybackBurner
 * @notice Swaps USDC for AgentMeme tokens via PancakeSwap V3 and burns them
 * @dev Called by AgentVault during epoch settlement to distribute 15% of profits to token burn
 */
contract BuybackBurner is Ownable {
    /// @notice The AgentMeme token to buy back and burn
    IERC20 public immutable agentMemeToken;

    /// @notice USDC token used for buyback
    IERC20 public immutable usdc;

    /// @notice PancakeSwap V3 Router address
    address public immutable pancakeRouter;

    /// @notice Total USDC spent on buybacks
    uint256 public totalUsdcSpent;

    /// @notice Total tokens burned
    uint256 public totalTokensBurned;

    /// @notice Emitted when tokens are bought back and burned
    event BuybackExecuted(
        uint256 usdcAmount,
        uint256 tokensBurned,
        uint256 timestamp
    );

    error InsufficientOutput();
    error SwapFailed();

    /**
     * @notice Constructor
     * @param _agentMemeToken Address of AgentMeme token
     * @param _usdc Address of USDC token
     * @param _pancakeRouter Address of PancakeSwap V3 Router
     */
    constructor(
        address _agentMemeToken,
        address _usdc,
        address _pancakeRouter
    ) Ownable(msg.sender) {
        require(_agentMemeToken != address(0), "Invalid token address");
        require(_usdc != address(0), "Invalid USDC address");
        require(_pancakeRouter != address(0), "Invalid router address");

        agentMemeToken = IERC20(_agentMemeToken);
        usdc = IERC20(_usdc);
        pancakeRouter = _pancakeRouter;
    }

    /**
     * @notice Execute buyback and burn
     * @param usdcAmount Amount of USDC to spend on buyback
     * @param minTokensOut Minimum tokens to receive (slippage protection)
     * @param deadline Transaction deadline
     */
    function executeBuyback(
        uint256 usdcAmount,
        uint256 minTokensOut,
        uint256 deadline
    ) external onlyOwner {
        require(usdcAmount > 0, "Amount must be > 0");
        require(deadline >= block.timestamp, "Deadline passed");

        // Transfer USDC from caller (AgentVault)
        require(
            usdc.transferFrom(msg.sender, address(this), usdcAmount),
            "USDC transfer failed"
        );

        // Approve router to spend USDC
        usdc.approve(pancakeRouter, usdcAmount);

        // Get token balance before swap
        uint256 balanceBefore = agentMemeToken.balanceOf(address(this));

        // Execute swap via PancakeSwap V3
        // Note: This is a simplified version. In production, use actual V3 router interface
        (bool success,) = pancakeRouter.call(
            abi.encodeWithSignature(
                "exactInputSingle((address,address,uint24,address,uint256,uint256,uint256,uint160))",
                usdc,                    // tokenIn
                address(agentMemeToken), // tokenOut
                3000,                    // fee (0.3%)
                address(this),           // recipient
                deadline,                // deadline
                usdcAmount,              // amountIn
                minTokensOut,            // amountOutMinimum
                0                        // sqrtPriceLimitX96 (no limit)
            )
        );

        if (!success) revert SwapFailed();

        // Calculate tokens received
        uint256 balanceAfter = agentMemeToken.balanceOf(address(this));
        uint256 tokensReceived = balanceAfter - balanceBefore;

        if (tokensReceived < minTokensOut) revert InsufficientOutput();

        // Burn the tokens by transferring to dead address
        require(
            agentMemeToken.transfer(address(0xdead), tokensReceived),
            "Burn failed"
        );

        // Update metrics
        totalUsdcSpent += usdcAmount;
        totalTokensBurned += tokensReceived;

        emit BuybackExecuted(usdcAmount, tokensReceived, block.timestamp);
    }

    /**
     * @notice Emergency function to recover accidentally sent tokens (not USDC or AgentMeme)
     * @param token Address of token to recover
     * @param amount Amount to recover
     */
    function recoverToken(address token, uint256 amount) external onlyOwner {
        require(token != address(usdc), "Cannot recover USDC");
        require(token != address(agentMemeToken), "Cannot recover AgentMeme");
        require(IERC20(token).transfer(owner(), amount), "Recovery failed");
    }
}
